const lead = $input.first().json.lead;
const sequenceType = $input.first().json.sequenceType || 'cold_outreach';

const templates = {
  cold_outreach: {
    subject: `Quick question about ${lead.companyName}`,
    body: `Hi ${lead.contactName || 'there'},\n\nI noticed ${lead.companyName} and wanted to reach out about how we help businesses like yours automate lead generation and outreach.\n\nWould you be open to a 15-minute call this week?\n\nBest,\nAiGateway Team`
  }
};

const template = templates[sequenceType] || templates.cold_outreach;

return [{ json: { lead, ...template, sequenceType } }];
